module virtual_memory_decoder (
    input [15:0] virtual_address,
    output [3:0] page_number,
    output [11:0] offset
);
    wire vm_addr_dec_page_num = virtual_address[15:12];
    assign page_number = vm_addr_dec_page_num; // Extracting the 4 most significant bits for page number
    assign offset = virtual_address[11:0];       // Extracting the 12 least significant bits for offset
endmodule
